import json
import os

# Get NYSE Arca ETFs - use the most recent query result
# The query_db:68 result should be available
nyse_arca_symbols = []

# Try to load from file if it exists
for i in range(60, 80):
    filename = f'/tmp/tmp_query_db_{i}.json'
    if os.path.exists(filename):
        try:
            with open(filename, 'r') as f:
                data = json.load(f)
                if len(data) > 0 and 'Symbol' in data[0]:
                    nyse_arca_symbols = [item['Symbol'] for item in data]
                    print(f"Loaded NYSE Arca ETFs from {filename}: {len(nyse_arca_symbols)}")
                    break
        except:
            continue

if not nyse_arca_symbols:
    print("Could not load NYSE Arca ETFs")

# Get trade tables
trade_tables = []
for i in range(70, 90):
    filename = f'/tmp/tmp_list_db_{i}.json'
    if os.path.exists(filename):
        try:
            with open(filename, 'r') as f:
                data = json.load(f)
                if isinstance(data, list):
                    trade_tables = data
                    print(f"Loaded trade tables from {filename}: {len(trade_tables)}")
                    break
        except:
            continue

if not trade_tables:
    print("Could not load trade tables")

print("__RESULT__:")
print(json.dumps({
    "nyse_arca_loaded": len(nyse_arca_symbols),
    "trade_tables_loaded": len(trade_tables)
}))

